130→            <button className={styles.backButton} onClick={() => navigate('/home')}>
131→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
132→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
133→                </svg>
134→                Back
135→            </button>
136→
137→            <div className={styles.coordsLabel}>
138→                {centerWorld.x}, {centerWorld.y}
139→            </div>
140→
141→            <Stage
142→                ref={stageRef}
143→                width={stageSize.width}
144→                height={stageSize.height}
145→                {...stageEvents}
