163→                    <button
164→                        className={styles.galaxyPreviewClose}
165→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
166→                    >
167→                        &times;
168→                    </button>
169→                    <div
170→                        className={styles.galaxyPreviewBg}
171→                        style={galaxyProfile.background || {}}
172→                    />
173→                    <div className={styles.galaxyPreviewContent}>
174→                        <img
175→                            className={styles.galaxyPreviewAvatar}
176→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
177→                            alt=""
178→                        />
179→                        <div className={styles.galaxyPreviewHeading}>
180→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
181→                        </div>
182→                        {galaxyProfile.bio && (
183→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
184→                        )}
185→                        <button
186→                            className={styles.galaxyPreviewVisitBtn}
187→                            onClick={(e) => handleClickProfile(navigate)(e, userId, selectedGalaxy.userId)}
188→                        >
189→                            Visit Profile
190→                        </button>
191→                    </div>
192→                </div>
193→            )}
194→
195→            {selectedPost && (
196→                <div className={styles.previewPanel}>
197→                    <button
198→                        className={styles.previewClose}
199→                        onClick={() => setSelectedPost(null)}
200→                    >
201→                        &times;
202→                    </button>
203→                    <div className={styles.previewAuthor}>
204→                        <img
205→                            className={styles.previewAvatar}
206→                            src={selectedPost.users?.image_url || '/assets/profile.jpg'}
207→                            alt=""
208→                        />
209→                        <span className={styles.previewAuthorName}>
210→                            {selectedPost.users?.name || 'Anonymous'}
211→                        </span>
212→                    </div>
213→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
214→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
215→                    <div className={styles.previewLikes}>
216→                        {Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count
217→                            ? `${selectedPost.likes[0].count} like${selectedPost.likes[0].count !== 1 ? 's' : ''}`
218→                            : '0 likes'}
219→                    </div>
220→                    <button className={styles.previewReadBtn} onClick={handleReadPost}>
221→                        Read
222→                    </button>
223→                </div>
224→            )}
225→        </div>
226→    );
227→};
