 1→import React from 'react';
 2→import { Circle } from 'react-konva';
 3→import { hexToRgba } from '../utils/starUtils';
 4→
 5→const Nebula = React.memo(({ x, y, radius, opacity, color }) => {
 6→    // 4 concentric circles at increasing opacity to simulate soft cloud glow
 7→    const layers = [
 8→        { rFactor: 1.0, opFactor: 0.3 },
 9→        { rFactor: 0.75, opFactor: 0.5 },
10→        { rFactor: 0.5, opFactor: 0.7 },
11→        { rFactor: 0.25, opFactor: 1.0 },
12→    ];
13→
14→    return layers.map((layer, i) => (
15→        <Circle
16→            key={i}
17→            x={x}
18→            y={y}
19→            radius={radius * layer.rFactor}
20→            fillRadialGradientStartPoint={{ x: 0, y: 0 }}
21→            fillRadialGradientEndPoint={{ x: 0, y: 0 }}
22→            fillRadialGradientStartRadius={0}
23→            fillRadialGradientEndRadius={radius * layer.rFactor}
24→            fillRadialGradientColorStops={[
25→                0, hexToRgba(color, opacity * layer.opFactor),
26→                1, hexToRgba(color, 0),
27→            ]}
28→            listening={false}
29→            perfectDrawEnabled={false}
30→        />
31→    ));
32→});
33→
34→Nebula.displayName = 'Nebula';
35→
36→export default Nebula;
