## 2. Database Schema Changes

### 2.1 New table: `galaxy_centroids`

```sql
-- server/sql/galaxy_gravity.sql

create table if not exists public.galaxy_centroids (
    user_id uuid primary key references auth.users(id) on delete cascade,
    mean_embedding vector(384),
    galaxy_x float,              -- settled galaxy center x
    galaxy_y float,              -- settled galaxy center y
    post_count int default 0,
    updated_at timestamptz default now()
);

create index if not exists galaxy_centroids_embedding_idx
on public.galaxy_centroids
using ivfflat (mean_embedding vector_cosine_ops)
with (lists = 50)
where mean_embedding is not null;
```

### 2.2 New table: `galaxy_edges`

```sql
create table if not exists public.galaxy_edges (
    user_a uuid references auth.users(id) on delete cascade,
    user_b uuid references auth.users(id) on delete cascade,
    similarity float not null,
    primary key (user_a, user_b),
    check (user_a < user_b)  -- canonical ordering to avoid duplicates
);

create index if not exists galaxy_edges_similarity_idx
on public.galaxy_edges (similarity desc);
```

### 2.3 New columns on `journals`

```sql
alter table public.journals
add column if not exists settled_x float,
add column if not exists settled_y float;
```

### 2.4 New RPC: compute mean embedding for a user

```sql
create or replace function public.compute_user_mean_embedding(target_user_id uuid)
returns vector(384)
language sql
stable
as $$
    select avg(embeddings)::vector(384)
    from public.journals
    where user_id = target_user_id
      and embeddings is not null
      and privacy = 'public';
$$;
```

### 2.5 New RPC: get galaxy edges for viewport

```sql
create or replace function public.get_galaxy_edges_in_viewport(
    vp_min_x float, vp_max_x float,
    vp_min_y float, vp_max_y float,
    min_similarity float default 0.3
)
returns table (
    user_a uuid,
    user_b uuid,
    similarity float
)
language sql
stable
as $$
    select e.user_a, e.user_b, e.similarity
    from public.galaxy_edges e
    join public.galaxy_centroids ca on ca.user_id = e.user_a
    join public.galaxy_centroids cb on cb.user_id = e.user_b
    where e.similarity >= min_similarity
      and (
          (ca.galaxy_x between vp_min_x and vp_max_x and ca.galaxy_y between vp_min_y and vp_max_y)
          or
          (cb.galaxy_x between vp_min_x and vp_max_x and cb.galaxy_y between vp_min_y and vp_max_y)
      );
$$;
```

### 2.6 New RPC: find similar post pairs in viewport

```sql
create or replace function public.find_similar_post_pairs(
    post_ids bigint[],
    threshold float default 0.9,
    max_pairs int default 50
)
returns table (
    post_a bigint,
    post_b bigint,
    similarity float
)
language sql
stable
as $$
    select
        a.id as post_a,
        b.id as post_b,
        1 - (a.embeddings <=> b.embeddings) as similarity
    from public.journals a
    join public.journals b on b.id > a.id
    where a.id = any(post_ids)
      and b.id = any(post_ids)
      and a.embeddings is not null
      and b.embeddings is not null
      and 1 - (a.embeddings <=> b.embeddings) >= threshold
    order by similarity desc
    limit max_pairs;
$$;
```

