// New state:
const [centroids, setCentroids] = useState(new Map()); // userId -> {galaxy_x, galaxy_y, post_count}
const [galaxyEdges, setGalaxyEdges] = useState([]);
const [similarPairs, setSimilarPairs] = useState([]);

// In the fetch effect, after receiving result:
if(result?.centroids) {
    setCentroids(prev => {
        const next = new Map(prev);
        for(const c of result.centroids) {
            next.set(c.user_id, c);
        }
        return next;
    });
}
if(result?.edges) setGalaxyEdges(result.edges);
if(result?.similarPairs) setSimilarPairs(result.similarPairs);

// Updated galaxies derivation:
const galaxies = useMemo(() => {
    const seen = new Map();
    for(const post of postArray) {
        const uid = post.users?.id || post.user_id;
        if(!uid || seen.has(uid)) continue;
        const centroid = centroids.get(uid);
        const home = centroid && centroid.galaxy_x != null
            ? { x: centroid.galaxy_x, y: centroid.galaxy_y }
            : userHomeCoords(uid); // fallback for unsettled galaxies
        seen.set(uid, {
            userId: uid,
            name: post.users?.name || post.user_name || 'Anonymous',
            x: home.x,
            y: home.y,
        });
    }
    return Array.from(seen.values());
}, [postArray, centroids]);

