### 4.6 Minimap Component: `client/src/components/Universe/components/UniverseMinimap.jsx`

A new component rendered as an HTML overlay (not inside the Konva Stage, to avoid performance impact on the main canvas).

```javascript
// Component: UniverseMinimap
// Props: galaxies, camera, zoom, stageSize, onNavigate
//
// Renders a small (160x160) canvas in the bottom-right corner.
// - Draws colored dots for each galaxy at scaled positions
// - Draws a viewport rectangle showing current view area
// - Clicking on the minimap calls onNavigate(worldX, worldY)
//
// Coordinate mapping:
//   WORLD_RANGE = 50000 (from -25000 to 25000)
//   MINIMAP_SIZE = 160
//   scale = MINIMAP_SIZE / WORLD_RANGE
//   galaxyScreenX = (galaxy.x + 25000) * scale
//   galaxyScreenY = (galaxy.y + 25000) * scale
//
// Viewport rect:
//   halfW = (stageSize.width / 2) / zoom
//   halfH = (stageSize.height / 2) / zoom
//   rectX = (camera.x - halfW + 25000) * scale
//   rectY = (camera.y - halfH + 25000) * scale
//   rectW = (halfW * 2) * scale
//   rectH = (halfH * 2) * scale

const UniverseMinimap = ({ galaxies, camera, zoom, stageSize, onNavigate }) => {
    const canvasRef = useRef(null);
    const MINIMAP_SIZE = 160;
    const WORLD_RANGE = 50000;
    const HALF_WORLD = 25000;

    useEffect(() => {
        const canvas = canvasRef.current;
        if(!canvas) return;
        const ctx = canvas.getContext('2d');
        const scale = MINIMAP_SIZE / WORLD_RANGE;

        // Clear
        ctx.clearRect(0, 0, MINIMAP_SIZE, MINIMAP_SIZE);

        // Background
        ctx.fillStyle = 'rgba(10, 14, 26, 0.85)';
        ctx.fillRect(0, 0, MINIMAP_SIZE, MINIMAP_SIZE);

        // Galaxy dots
        for(const g of galaxies) {
            const sx = (g.x + HALF_WORLD) * scale;
            const sy = (g.y + HALF_WORLD) * scale;
            ctx.fillStyle = getStarColor(g.userId);
            ctx.globalAlpha = 0.7;
            ctx.beginPath();
            ctx.arc(sx, sy, 2, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.globalAlpha = 1;

        // Viewport rect
        const halfW = (stageSize.width / 2) / zoom;
        const halfH = (stageSize.height / 2) / zoom;
        const rx = (camera.x - halfW + HALF_WORLD) * scale;
        const ry = (camera.y - halfH + HALF_WORLD) * scale;
        const rw = (halfW * 2) * scale;
        const rh = (halfH * 2) * scale;
        ctx.strokeStyle = 'rgba(255,255,255,0.5)';
        ctx.lineWidth = 1;
        ctx.strokeRect(rx, ry, rw, rh);
    }, [galaxies, camera, zoom, stageSize]);

    const handleClick = useCallback((e) => {
        const rect = e.target.getBoundingClientRect();
        const mx = e.clientX - rect.left;
        const my = e.clientY - rect.top;
        const scale = MINIMAP_SIZE / WORLD_RANGE;
        const worldX = mx / scale - HALF_WORLD;
        const worldY = my / scale - HALF_WORLD;
        onNavigate(worldX, worldY);
    }, [onNavigate]);

    return (
        <canvas
            ref={canvasRef}
            width={MINIMAP_SIZE}
            height={MINIMAP_SIZE}
            onClick={handleClick}
            className={styles.minimap}
        />
    );
};
```

